// Expand offense into (provider x target) work items.
const input = $input.first().json;
const caseId = input.case_id;

function isPublicIp(ip) {
  if (!ip || ip === 'unknown') return false;
  const m = ip.match(/^(\d+)\.(\d+)\.(\d+)\.(\d+)$/);
  if (!m) return false;
  const o = m.slice(1).map(Number);
  if (o.some(x => x > 255)) return false;
  if (o[0] === 10) return false;
  if (o[0] === 127) return false;
  if (o[0] === 169 && o[1] === 254) return false;
  if (o[0] === 172 && o[1] >= 16 && o[1] <= 31) return false;
  if (o[0] === 192 && o[1] === 168) return false;
  if (o[0] === 0) return false;
  return true;
}

const PROVIDERS_BY_TYPE = {
  ip: ['abuseipdb', 'shodan', 'otx'],
  domain: ['otx'],
  url: ['otx'],
  hash: ['otx']
};

// Collect unique targets
const targets = [];
const seen = new Set();
function addTarget(value, type) {
  if (!value || value === 'unknown') return;
  const k = type + ':' + value;
  if (seen.has(k)) return;
  seen.add(k);
  targets.push({ value, type });
}

const itype = (input.indicator_type || '').toLowerCase();
const normType = ['ip','ipv4','ip-src'].includes(itype) ? 'ip'
  : ['domain','hostname'].includes(itype) ? 'domain'
  : ['url'].includes(itype) ? 'url'
  : ['hash','md5','sha1','sha256','file'].includes(itype) ? 'hash'
  : null;
if (normType) addTarget(input.indicator, normType);
if (isPublicIp(input.source_ip)) addTarget(input.source_ip, 'ip');

// Fan out to provider work items
const items = [];
for (const t of targets) {
  const providers = PROVIDERS_BY_TYPE[t.type] || [];
  for (const provider of providers) {
    items.push({
      json: {
        case_id: caseId,
        target_value: t.value,
        target_type: t.type,
        provider,
        cache_key: `enrich:${provider}:${t.type}:${t.value}`
      }
    });
  }
}

// If nothing to enrich, emit a single sentinel so downstream note step can still run
if (items.length === 0) {
  return [{ json: { case_id: caseId, target_value: null, target_type: null, provider: null, cache_key: null, _empty: true } }];
}
return items;

return $input.all().map(item => {
  const j = item.json;
  let result = null;
  try { result = JSON.parse(j.cached_raw); } catch (e) { result = { provider: j.provider, ok: false, data: null }; }
  return { json: { case_id: j.case_id, target_value: j.target_value, target_type: j.target_type, provider: j.provider, result } };
});

// Normalize whichever provider produced this item. Best-effort: HTTP errors
// arrive as items with an `error` field or non-2xx; mark ok=false.
return $input.all().map(item => {
  const j = item.json;
  const provider = j.provider;
  const base = { case_id: j.case_id, target_value: j.target_value, target_type: j.target_type, provider };
  // n8n continueRegularOutput puts failures in j.error or leaves body empty
  const failed = j.error !== undefined || j.statusCode >= 500 || (j.body && j.body.error);
  let data = null, ok = false;
  try {
    if (provider === 'abuseipdb' && j.data) { data = { confidence: j.data.abuseConfidenceScore, reports: j.data.totalReports, country: j.data.countryCode }; ok = true; }
    else if (provider === 'shodan') {
      if (j.ports || j.data || j.vulns) { data = { ports: j.ports || [], vulns: Object.keys(j.vulns || {}), org: j.org || null }; ok = true; }
      else if (j.statusCode === 404 || (j.error && String(j.error).includes('404'))) { data = { ports: [], vulns: [], org: null, note: 'no shodan info' }; ok = true; }
    }
    else if (provider === 'otx' && j.pulse_info) { data = { pulses: j.pulse_info.count || 0, top: (j.pulse_info.pulses || []).slice(0,3).map(p => p.name) }; ok = true; }
  } catch (e) { ok = false; }
  if (failed && !ok) ok = false;
  return { json: { ...base, result: { provider, ok, data: ok ? data : null } } };
});
